import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void threeClustersDifferentSums() {
        int[][] grid = {
            {5, 3, 0},
            {0, 2, 0},
            {7, 0, 8}
        };
        // Cluster A: (0,0)+(0,1)+(1,1) = 10; Cluster B: (2,0) = 7; Cluster C: (2,2) = 8
        assertEquals(10L, new Solution().maxClusterRisk(grid));
    }

    @Test
    void allZeros() {
        int[][] grid = {
            {0, 0},
            {0, 0}
        };
        assertEquals(0L, new Solution().maxClusterRisk(grid));
    }

    @Test
    void singlePositiveCell() {
        int[][] grid = {{4}};
        assertEquals(4L, new Solution().maxClusterRisk(grid));
    }

    @Test
    void emptyGrid() {
        int[][] grid = {};
        assertEquals(0L, new Solution().maxClusterRisk(grid));
    }

    @Test
    void fourIsolatedClusters_maxIsFour() {
        int[][] grid = {
            {1, 0, 2},
            {0, 0, 0},
            {3, 0, 4}
        };
        assertEquals(4L, new Solution().maxClusterRisk(grid));
    }

    @Test
    void largeSingleCluster() {
        // One big connected region whose sum exceeds int range
        // Approximate overflow check: 6 cells each with 400_000_000
        int[][] grid = {
            {400_000_000, 400_000_000, 400_000_000},
            {400_000_000, 400_000_000, 400_000_000}
        };
        assertEquals(2_400_000_000L, new Solution().maxClusterRisk(grid));
    }

    @Test
    void zeroSeparatesTwoClusters_biggerWins() {
        int[][] grid = {
            {10, 20, 0, 1},
            {5,  0,  0, 2}
        };
        // Cluster A: (0,0)=10 + (0,1)=20 + (1,0)=5 = 35
        // Cluster B: (0,3)=1 + (1,3)=2 = 3
        assertEquals(35L, new Solution().maxClusterRisk(grid));
    }
}
